population.algorithm:
For each order, select best vehicle among top-3 nearest by minimizing marginal cost increase plus weighted distance; fallback to new route or first-fit if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const topK = 3
	const weightDist = 0.03

	for jj := range oris {
		type cand struct {
			idx  int
			dist float64
		}
		var topCands [topK]cand
		topLen := 0

		// collect topK nearest non-empty assigns
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			if dispatch.Assigns[ii].StationsLen <= 0 {
				continue
			}
			dist := cal_dis(dispatch.Assigns[ii].StationCurrent, oris[jj])
			pos := topLen
			if pos >= topK {
				pos = topK - 1
				if dist >= topCands[pos].dist {
					continue
				}
			} else {
				topLen++
			}
			for pos > 0 && dist < topCands[pos-1].dist {
				topCands[pos] = topCands[pos-1]
				pos--
			}
			topCands[pos] = cand{idx: ii, dist: dist}
		}

		// evaluate topK candidates
		bestIdx := -1
		bestScore := 1e18
		for pos := 0; pos < topLen; pos++ {
			ii := topCands[pos].idx
			oldCost := dispatch.Assigns[ii].Cost
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				continue
			}
			dispatch.Assigns[ii].GenRoute()
			newCost := dispatch.Assigns[ii].Cost
			if newCost >= 0 {
				score := (newCost - oldCost) + weightDist*topCands[pos].dist
				if score < bestScore {
					bestScore = score
					bestIdx = ii
				}
			}
			// rollback
			dispatch.Assigns[ii].RemoveShip(total_ship + jj)
			dispatch.Assigns[ii].GenRoute()
		}

		if bestIdx >= 0 {
			// commit best
			dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[bestIdx].GenRoute()
			continue
		}

		// try to open a new empty assign
		if dispatch.AssignsLen < MAXASSIGNS {
			ii := dispatch.AssignsLen
			if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[ii].GenRoute()
				if dispatch.Assigns[ii].Cost >= 0 {
					dispatch.AssignsLen = ii + 1
					continue
				}
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			}
		}

		// fallback: first-fit among all existing assigns (including those not in topK)
		inserted := false
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			if dispatch.Assigns[ii].StationsLen <= 0 {
				continue
			}
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				continue
			}
			dispatch.Assigns[ii].GenRoute()
			if dispatch.Assigns[ii].Cost >= 0 {
				inserted = true
				break
			}
			dispatch.Assigns[ii].RemoveShip(total_ship + jj)
			dispatch.Assigns[ii].GenRoute()
		}
		if !inserted && dispatch.AssignsLen < MAXASSIGNS {
			ii := dispatch.AssignsLen
			if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[ii].GenRoute()
				if dispatch.Assigns[ii].Cost >= 0 {
					dispatch.AssignsLen = ii + 1
				}
			}
		}
		// if still not inserted, skip this order (no feasible assignment exists)
	}

	dispatch.RenewnTotalCost()
	return dispatch

