// Helper to attempt AddShip, GenRoute, and rollback on failure
tryAdd := func(assign *Assign, shipID int, ori, des Station) (bool, float64) {
	if !assign.AddShip(shipID, ori, des) {
		return false, -1
	}
	assign.GenRoute()
	if assign.Cost < 0 {
		assign.RemoveShip(shipID)
		assign.GenRoute()
		return false, -1
	}
	return true, assign.Cost
}

// Detect tight time-windows
tightWindow := false
for i := range oris {
	if oris[i].TimeEnd-oris[i].TimeStart <= 0 || dess[i].TimeEnd-dess[i].TimeStart <= 0 {
		tightWindow = true
		break
	}
}

if len(oris) <= 5 && !tightWindow {
	// Small batch, loose windows: top-2 distance heuristic
	topK, alpha := 2, 0.03
	for jj := range oris {
		type cand struct {
			idx  int
			dist float64
		}
		var candidates []cand
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			if dispatch.Assigns[ii].StationsLen > 0 {
				dist := cal_dis(dispatch.Assigns[ii].StationCurrent, oris[jj])
				candidates = append(candidates, cand{ii, dist})
			}
		}
		// Partial sort for topK
		for i := 0; i < len(candidates)-1; i++ {
			for j := i + 1; j < len(candidates); j++ {
				if candidates[j].dist < candidates[i].dist {
					candidates[i], candidates[j] = candidates[j], candidates[i]
				}
			}
		}
		limit := topK
		if limit > len(candidates) {
			limit = len(candidates)
		}

		bestIdx := -1
		bestScore := 1e18
		for k := 0; k < limit; k++ {
			ii := candidates[k].idx
			oldCost := dispatch.Assigns[ii].Cost
			ok, newCost := tryAdd(&dispatch.Assigns[ii], total_ship+jj, oris[jj], dess[jj])
			if ok {
				score := (newCost - oldCost) + alpha*candidates[k].dist
				if score < bestScore {
					bestScore = score
					bestIdx = ii
				}
				// Rollback trial insertion
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			}
		}

		if bestIdx >= 0 {
			// Apply best insertion
			dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[bestIdx].GenRoute()
		} else {
			// Fallback: try any existing assign (including empty ones) in order, then new
			inserted := false
			for ii := 0; ii < dispatch.AssignsLen; ii++ {
				ok, _ := tryAdd(&dispatch.Assigns[ii], total_ship+jj, oris[jj], dess[jj])
				if ok {
					inserted = true
					break
				}
			}
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				ii := dispatch.AssignsLen
				ok, _ := tryAdd(&dispatch.Assigns[ii], total_ship+jj, oris[jj], dess[jj])
				if ok {
					dispatch.AssignsLen = ii + 1
				}
			}
		}
	}
} else if len(oris) <= 10 && !tightWindow {
