Deterministic greedy insertion: for each order, evaluate insertion into all active vehicles, selecting the one with minimal incremental cost (new-old)+distance*1e-4 tie-breaker. If no active vehicle accepts the order, open a new vehicle up to MAXASSIGNS; as a last resort, try every vehicle (including unused slots) to guarantee insertion unless completely infeasible.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for jj := range oris {
		bestIdx := -1
		bestScore := 1e18

		// Evaluate insertion into every active vehicle
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			if dispatch.Assigns[ii].StationsLen <= 0 {
				continue
			}
			oldCost := dispatch.Assigns[ii].Cost
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				continue
			}
			dispatch.Assigns[ii].GenRoute()
			newCost := dispatch.Assigns[ii].Cost
			if newCost >= 0 {
				inc := newCost - oldCost
				if inc < 0 {
					inc = 0
				}
				dist := cal_dis(dispatch.Assigns[ii].StationCurrent, oris[jj])
				score := inc + dist*1e-4
				if score < bestScore {
					bestScore = score
					bestIdx = ii
				}
			}
			dispatch.Assigns[ii].RemoveShip(total_ship + jj)
			dispatch.Assigns[ii].GenRoute()
		}

		if bestIdx >= 0 {
			// Best existing vehicle found
			if dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[bestIdx].GenRoute()
			}
