// Helper: a large number for best score initialisation.
const MAX_SCORE = 1e18
const DIST_PENALTY = 0.001

for jj := range oris {
	bestScore := MAX_SCORE
	bestIdx := -1
	bestIsNew := false

	// Evaluate all existing non‑empty assignments.
	for ii := 0; ii < dispatch.AssignsLen; ii++ {
		if dispatch.Assigns[ii].StationsLen <= 0 {
			continue
		}
		oldCost := dispatch.Assigns[ii].Cost
		if oldCost < 0 { // should not happen, but be safe
			continue
		}
		// Distance penalty from current station to origin.
		dist := cal_dis(dispatch.Assigns[ii].StationCurrent, oris[jj])

		if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
			continue
		}
		dispatch.Assigns[ii].GenRoute()
		newCost := dispatch.Assigns[ii].Cost
		if newCost >= 0 {
			score := (newCost - oldCost) + DIST_PENALTY*dist
			if score < bestScore {
				bestScore = score
				bestIdx = ii
				bestIsNew = false
			}
		}
		// Always rollback tentative insertion.
		dispatch.Assigns[ii].RemoveShip(total_ship + jj)
		dispatch.Assigns[ii].GenRoute()
	}

	// Evaluate a new (empty) assignment if there is room.
	if dispatch.AssignsLen < MAXASSIGNS {
		idx := dispatch.AssignsLen
		if dispatch.Assigns[idx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
			dispatch.Assigns[idx].GenRoute()
			newCost := dispatch.Assigns[idx].Cost
			if newCost >= 0 {
				// No old cost, no distance penalty.
				score := newCost
