New algorithm: Evaluate top-3 nearest vehicles by incremental cost and time-window tightness factor, fallback to full distance-sorted scan and new vehicle creation, processing all orders without early exit.}

func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const topK = 3
	tightWindow := false
	for jj := range oris {
		if oris[jj].TimeEnd-oris[jj].TimeStart < 0 || dess[jj].TimeEnd-dess[jj].TimeStart < 0 {
			tightWindow = true
			break
		}
	}
	weight := 0.03
	if tightWindow {
		weight = 0.1
	}

	for jj := range oris {
		// Build list of candidate vehicles with distances
		type cand struct {
			idx  int
			dist float64
		}
		var candidates []cand
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			if dispatch.Assigns[ii].StationsLen <= 0 {
				continue
			}
			d := cal_dis(dispatch.Assigns[ii].StationCurrent, oris[jj])
			candidates = append(candidates, cand{ii, d})
		}
		// Sort by distance
		// Simple insertion sort
		for i := 1; i < len(candidates); i++ {
			for k := i; k > 0 && candidates[k].dist < candidates[k-1].dist; k-- {
				candidates[k], candidates[k-1] = candidates[k-1], candidates[k]
			}
		}

		// Top-K evaluation
		bestIdx := -1
		bestScore := 1e18
		evalLimit := topK
		if len(candidates) < evalLimit {
			evalLimit = len(candidates)
		}
		for pos := 0; pos < evalLimit; pos++ {
			ii := candidates[pos].idx
			oldCost := dispatch.Assigns[ii].Cost
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				continue
			}
			dispatch.Assigns[ii].GenRoute()
			newCost := dispatch.Assigns[ii].Cost
			if newCost >= 0 {
				score := (newCost - oldCost) + weight*candidates[pos].dist
				if score < bestScore {
					bestScore = score
					bestIdx = ii
				}
			}
			dispatch.Assigns[ii].RemoveShip(total_ship + jj)
			dispatch.Assigns[ii].GenRoute()
		}

		inserted := false
		if bestIdx >= 0 {
			dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[bestIdx].GenRoute()
			inserted = true
		}

		// Fallback: try all candidates in distance order if top-K didn't succeed
		if !inserted {
			for _, c := range candidates {
				ii := c.idx
				if dispatch.Assigns[ii].Cost < 0 {
					continue
				}
				if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
					continue
				}
				dispatch.Assigns[ii].GenRoute()
				if dispatch.Assigns[ii].Cost >= 0 {
					inserted = true
					break
				}
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			}
		}

		// Fallback: try to create a new vehicle
		if !inserted && dispatch.AssignsLen < MAXASSIGNS {
			for ii := dispatch.AssignsLen; ii < MAXASSIGNS; ii++ {
				if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
					continue
				}
				dispatch.Assigns[ii].GenRoute()
				if dispatch.Assigns[ii].Cost >= 0 {
					dispatch.AssignsLen = ii + 1
					inserted = true
					break
				}
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			}
		}

		// If still not inserted, drop silently and continue
	}
	dispatch.RenewnTotalCost()
	return dispatch

