Top-3 nearest insertion with weighted cost+distance score and shuffle-based fallback to guarantee all orders are assigned.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const topK = 3
	const weight = 0.05

	for jj := range oris {
		var topIdx [topK]int
		var topDist [topK]float64
		topLen := 0

		// collect up to topK nearest non-empty assignments
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			if dispatch.Assigns[ii].StationsLen <= 0 {
				continue
			}
			dist := cal_dis(dispatch.Assigns[ii].StationCurrent, oris[jj])
			pos := topLen
			if pos >= topK {
				pos = topK - 1
				if dist >= topDist[pos] {
					continue
				}
			} else {
				topLen++
			}
			for pos > 0 && dist < topDist[pos-1] {
				topIdx[pos] = topIdx[pos-1]
				topDist[pos] = topDist[pos-1]
				pos--
			}
			topIdx[pos] = ii
			topDist[pos] = dist
		}

		// evaluate top-K and pick best
		bestIdx := -1
		bestScore := 1e18
		for pos := 0; pos < topLen; pos++ {
			ii := topIdx[pos]
			oldCost := dispatch.Assigns[ii].Cost
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				continue
			}
			dispatch.Assigns[ii].GenRoute()
			newCost := dispatch.Assigns[ii].Cost
			if newCost >= 0 {
				score := (newCost - oldCost) + weight*topDist[pos]
				if score < bestScore {
					bestScore = score
					bestIdx = ii
				}
			}
			// rollback
			dispatch.Assigns[ii].RemoveShip(total_ship + jj)
			dispatch.Assigns[ii].GenRoute()
		}

		if bestIdx >= 0 {
			dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[bestIdx].GenRoute()
			if bestIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = bestIdx + 1
			}
			continue
		}

		// try a brand-new assignment
		if dispatch.AssignsLen < MAXASSIGNS {
			ii := dispatch.AssignsLen
			if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[ii].GenRoute()
				if dispatch.Assigns[ii].Cost >= 0 {
					dispatch.AssignsLen = ii + 1
					continue
				}
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			}
		}

		// fallback: shuffle-based insertion to guarantee assignment
		var randRange [MAXASSIGNS]int
		randLimit := 0
		for ii := range randRange {
			randRange[ii] = ii
			if ii < dispatch.AssignsLen && dispatch.Assigns[ii].StationsLen > 0 {
				randRange[ii], randRange[randLimit] = randRange[randLimit], ii
				randLimit++
			}
		}
		rand.Shuffle(randLimit, func(i, j int) {
			randRange[i], randRange[j] = randRange[j], randRange[i]
		})

		inserted := false
		for _, ii := range randRange {
			if ii >= MAXASSIGNS {
				continue
			}
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[ii].Cost = -1
			} else {
				dispatch.Assigns[ii].GenRoute()
			}
			if dispatch.Assigns[ii].Cost < 0 {
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			} else {
				if ii >= dispatch.AssignsLen {
					dispatch.AssignsLen = ii + 1
				}
				inserted = true
				break
			}
		}

		if !inserted && dispatch.AssignsLen < MAXASSIGNS {
			ii := dispatch.AssignsLen
			if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[ii].GenRoute()
				if dispatch.Assigns[ii].Cost >= 0 {
					dispatch.AssignsLen = ii + 1
				} else {
					dispatch.Assigns[ii].RemoveShip(total_ship + jj)
					dispatch.Assigns[ii].GenRoute()
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

