A deterministic insertion heuristic that for each order selects the top 2 or 3 closest non-empty assignments by distance, temporarily inserts to evaluate cost increase plus a small distance penalty, permanently places in the assignment with minimal score, and falls back to sequential insertion if no candidate works.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	topK := 3
	if len(oris) <= 5 {
		topK = 2
	}

	for jj := range oris {
		var topIdx [3]int
		var topDist [3]float64
		topLen := 0

		// find topK closest non‑empty assignments
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			if dispatch.Assigns[ii].StationsLen <= 0 {
				continue
			}
			dist := cal_dis(dispatch.Assigns[ii].StationCurrent, oris[jj])
			pos := topLen
			if pos >= topK {
				pos = topK - 1
				if dist >= topDist[pos] {
					continue
				}
			} else {
				topLen++
			}
			for pos > 0 && dist < topDist[pos-1] {
				topIdx[pos] = topIdx[pos-1]
				topDist[pos] = topDist[pos-1]
				pos--
			}
			topIdx[pos] = ii
			topDist[pos] = dist
		}

		bestIdx := -1
		bestScore := 1e18
		// evaluate candidates and keep the one with smallest cost increase
		for pos := 0; pos < topLen; pos++ {
			ii := topIdx[pos]
			oldCost := dispatch.Assigns[ii].Cost
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				continue
			}
			dispatch.Assigns[ii].GenRoute()
			newCost := dispatch.Assigns[ii].Cost
			if newCost >= 0 {
				score := (newCost - oldCost) + 0.01*topDist[pos]
				if score < bestScore {
					bestScore = score
					bestIdx = ii
				}
			}
			// rollback tentative insertion
			dispatch.Assigns[ii].RemoveShip(total_ship + jj)
			dispatch.Assigns[ii].GenRoute()
		}

		if bestIdx >= 0 {
			// commit to the best candidate
			dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[bestIdx].GenRoute()
		} else {
			// fallback: sequential insertion into any existing non‑empty assignment
			inserted := false
			for ii := 0; ii < dispatch.AssignsLen; ii++ {
				if dispatch.Assigns[ii].StationsLen <= 0 {
					continue
				}
				if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
					continue
				}
				dispatch.Assigns[ii].GenRoute()
				if dispatch.Assigns[ii].Cost >= 0 {
					inserted = true
					break
				}
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			}
			// try new assignment if fallback failed
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				ii := dispatch.AssignsLen
				if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
					dispatch.Assigns[ii].GenRoute()
					if dispatch.Assigns[ii].Cost >= 0 {
						dispatch.AssignsLen = ii + 1
						inserted = true
					} else {
						dispatch.Assigns[ii].RemoveShip(total_ship + jj)
						dispatch.Assigns[ii].GenRoute()
					}
				}
			}
			// if even the new assignment fails the order cannot be served – skip it silently
			_ = inserted
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

