Regret-based insertion that evaluates cost increase plus distance penalty for each existing route, and if multiple routes have similar scores, opens a new vehicle to preserve flexibility, with a sequential first-feasible fallback for any order that cannot be placed otherwise.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const regretThreshold = 0.5
	const distWeight = 0.1

	for jj := range oris {
		bestIdx := -1
		bestScore := 1e18
		secondBestScore := 1e18

		// Evaluate insertion into every existing non-empty route
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			if dispatch.Assigns[ii].StationsLen <= 0 {
				continue
			}
			oldCost := dispatch.Assigns[ii].Cost
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				continue
			}
			dispatch.Assigns[ii].GenRoute()
			newCost := dispatch.Assigns[ii].Cost
			if newCost < 0 {
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
				continue
			}
			inc := newCost - oldCost
			dist := cal_dis(dispatch.Assigns[ii].StationCurrent, oris[jj])
			score := inc + distWeight*dist

			// Clean up tentative insertion
			dispatch.Assigns[ii].RemoveShip(total_ship + jj)
			dispatch.Assigns[ii].GenRoute()

			if score < bestScore {
				secondBestScore = bestScore
				bestScore = score
				bestIdx = ii
			} else if score < secondBestScore {
				secondBestScore = score
			}
		}

		inserted := false

		// Decision: use best route if regret is high, otherwise favour a new vehicle
		if bestIdx != -1 {
			regret := secondBestScore - bestScore
			if secondBestScore == 1e18 {
				regret = regretThreshold + 1.0
			}
			if regret > regretThreshold {
				// Clear winner
				if dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
					dispatch.Assigns[bestIdx].GenRoute()
					if dispatch.Assigns[bestIdx].Cost >= 0 {
						inserted = true
					} else {
						dispatch.Assigns[bestIdx].RemoveShip(total_ship + jj)
						dispatch.Assigns[bestIdx].GenRoute()
					}
				}
			} else {
				// Close competition – try to open a new vehicle first
				if dispatch.AssignsLen < MAXASSIGNS {
					newIdx := dispatch.AssignsLen
					if dispatch.Assigns[newIdx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
						dispatch.Assigns[newIdx].GenRoute()
						if dispatch.Assigns[newIdx].Cost >= 0 {
							dispatch.AssignsLen = newIdx + 1
							inserted = true
						} else {
							dispatch.Assigns[newIdx].RemoveShip(total_ship + jj)
							dispatch.Assigns[newIdx].GenRoute()
						}
					}
				}
				// Fallback to best existing if new vehicle failed
				if !inserted {
					if dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
						dispatch.Assigns[bestIdx].GenRoute()
						if dispatch.Assigns[bestIdx].Cost >= 0 {
							inserted = true
						} else {
							dispatch.Assigns[bestIdx].RemoveShip(total_ship + jj)
							dispatch.Assigns[bestIdx].GenRoute()
						}
					}
				}
			}
		}

		// No feasible existing route found – try new vehicle directly
		if !inserted && dispatch.AssignsLen < MAXASSIGNS {
			newIdx := dispatch.AssignsLen
			if dispatch.Assigns[newIdx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[newIdx].GenRoute()
				if dispatch.Assigns[newIdx].Cost >= 0 {
