Deterministic best-fit insertion evaluates all non-empty vehicles by tentative add, selects minimal cost-increment candidate, commits it; if none feasible, tries a new vehicle; and falls back to sequential first-fit for robustness.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for jj := range oris {
		bestIdx := -1
		bestScore := 1e18

		// Evaluate all existing non-empty vehicles
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			if dispatch.Assigns[ii].StationsLen <= 0 {
				continue
			}
			oldCost := dispatch.Assigns[ii].Cost
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				continue
			}
			dispatch.Assigns[ii].GenRoute()
			newCost := dispatch.Assigns[ii].Cost
			if newCost >= 0 {
				score := (newCost - oldCost) + 0.01*cal_dis(dispatch.Assigns[ii].StationCurrent, oris[jj])
				if score < bestScore {
					bestScore = score
					bestIdx = ii
				}
			}
			// Rollback tentative insertion
			dispatch.Assigns[ii].RemoveShip(total_ship + jj)
			dispatch.Assigns[ii].GenRoute()
		}

		inserted := false
		if bestIdx >= 0 {
			if dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[bestIdx].GenRoute()
				if dispatch.Assigns[bestIdx].Cost >= 0 {
					inserted = true
				} else {
					dispatch.Assigns[bestIdx].RemoveShip(total_ship + jj)
					dispatch.Assigns[bestIdx].GenRoute()
				}
			}
		}

		if !inserted && dispatch.AssignsLen < MAXASSIGNS {
			ii := dispatch.AssignsLen
			if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[ii].GenRoute()
				if dispatch.Assigns[ii].Cost >= 0 {
					dispatch.AssignsLen = ii + 1
					inserted = true
				} else {
					dispatch.Assigns[ii].RemoveShip(total_ship + jj)
					dispatch.Assigns[ii].GenRoute()
				}
			}
		}

		if !inserted {
			// Safe fallback: first-fit over all possible vehicle slots
			for ii := 0; ii < MAXASSIGNS; ii++ {
				if ii < dispatch.AssignsLen && dispatch.Assigns[ii].StationsLen <= 0 {
					continue
				}
				if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
					dispatch.Assigns[ii].Cost = -1
				} else {
					dispatch.Assigns[ii].GenRoute()
				}
				if dispatch.Assigns[ii].Cost >= 0 {
					if ii >= dispatch.AssignsLen {
						dispatch.AssignsLen = ii + 1
					}
					inserted = true
					break
				}
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			}
		}
		// If still not inserted, the order is infeasible; continue processing remaining orders
	}
	dispatch.RenewnTotalCost()
	return dispatch

